// Calcula a semana atual e monta checklist de conteúdo
const hoje = new Date();
const inicio2026 = new Date('2026-01-04'); // primeira semana
const diffMs = hoje - inicio2026;
const diffSemanas = Math.floor(diffMs / (7 * 24 * 60 * 60 * 1000));
const semanaNum = (diffSemanas % 8) + 1; // ciclo de 8 semanas

// Cronograma de temas por semana
const temas = {
  1: {
    nome: 'Fundamentos NR-1',
    seg: 'Carrossel: O que mudou na NR-1 em 2024 (linha do tempo)',
    ter: 'Reels: Empresa multada por não ter PGR',
    qui: 'Carrossel: 5 erros que geram autuação',
    sex: 'Reels: Por que Guilherme escreveu esse eBook'
  },
  2: {
    nome: 'Riscos Psicossociais',
    seg: 'Carrossel: O que são riscos psicossociais (5 grupos)',
    ter: 'Reels: Funcionário afastado por burnout — a empresa pagou',
    qui: 'Carrossel: Checklist — sua empresa tem esses 5 riscos?',
    sex: 'Reels: Isso não é papelada — é gestão de pessoas'
  },
  3: {
    nome: 'PGR na Prática',
    seg: 'Carrossel: PGR — o que é, quem precisa, como fazer',
    ter: 'Reels: Auditoria surpresa — o que o fiscal procura primeiro',
    qui: 'Carrossel: PGR genérico vs. PGR real',
    sex: 'Reels: O que aprendi ajudando empresas com a NR-1'
  },
  4: {
    nome: 'Custo de Não Agir',
    seg: 'Carrossel: Infográfico multa + MPT + passivo trabalhista',
    ter: 'Reels: Empresa interditada — o que aconteceu',
    qui: 'Carrossel: Calculadora de risco de exposição',
    sex: 'Reels: Adequar custa uma fração do que não adequar'
  },
  5: {
    nome: 'Checklist Prático',
    seg: 'Carrossel: Capítulo 5 do eBook — checklist inicial',
    ter: 'Reels: Em 1 tarde você pode tirar sua empresa da zona de risco',
    qui: 'Carrossel: Passo a passo — do zero à proteção',
    sex: 'Reels: Depoimento de cliente que implementou'
  },
  6: {
    nome: 'Autoridade',
    seg: 'Carrossel: Quem é Guilherme Avelar (história + credenciais)',
    ter: 'Reels: Gestão + tributos + SST — a combinação que ninguém tem',
    qui: 'Carrossel: Parceria com profissional SST habilitado',
    sex: 'Reels: Não sou especialista em segurança — sou em empresas'
  },
  7: {
    nome: 'Empatia com o Dono',
    seg: 'Carrossel: Você tem 5 a 200 funcionários? É com você.',
    ter: 'Reels: A padaria, a clínica, a loja — todos têm obrigação',
    qui: 'Carrossel: Dono que descobriu tarde — o que mudou',
    sex: 'Reels: Não precisa virar especialista. Precisa estar protegido.'
  },
  8: {
    nome: 'Produto + CTA',
    seg: 'Carrossel: O que está no eBook (preview dos capítulos)',
    ter: 'Reels: R$27 que podem evitar R$XX.000 de multa',
    qui: 'Carrossel: Grupo WhatsApp — o que você recebe lá dentro',
    sex: 'Reels: Guilherme — convite direto para o grupo'
  }
};

const semana = temas[semanaNum] || temas[1];

// Data de amanhã (segunda)
const amanha = new Date(hoje.getTime() + 24 * 60 * 60 * 1000);
const dataStr = amanha.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });

let msg = `📅 SEMANA ${semanaNum}/8 — ${semana.nome}\n`;
msg += `Empresa Protegida™ · inicia ${dataStr}\n\n`;
msg += `Programação:\n`;
msg += `• SEG 7h30: ${semana.seg}\n`;
msg += `• TER 19h: ${semana.ter}\n`;
msg += `• QUI 18h: ${semana.qui}\n`;
msg += `• SEX 7h30: ${semana.sex}\n`;
msg += `• SAB 10h: Feed foto (quote ou autoridade)\n\n`;
msg += `✅ Checklist de produção:\n`;
msg += `□ Roteiro do Reels de terça\n`;
msg += `□ Slides do carrossel de segunda\n`;
msg += `□ Arte/foto para sexta\n`;
msg += `□ Stories de quarta (enquete/quiz)\n`;
msg += `□ Post de sábado (foto + legenda)\n\n`;
msg += `💡 Ferramenta: Canva (carrosséis) + CapCut (Reels)`;

return [{ json: { mensagem: msg } }];
